import { useEffect, useState } from "react";
import { notes as defaultNotes } from "./notes";
import LZString from "lz-string";

export const NOTES_STORAGE_KEY = "jar-notes-v1";
export const RECIPIENT_STORAGE_KEY = "jar-recipient-v1";

// Token format: compressed delta-encoded payload
// Delta = only notes that differ from defaults + recipient name
// This produces URLs ~80-95% shorter than encoding all 100 notes.

// Caching decoded token to prevent expensive decode cycles on every render
let cachedDecodedToken: { notes: string[]; recipient: string } | null = null;
let hasDecodedToken = false;

function getDecodedToken(): { notes: string[]; recipient: string } | null {
  if (typeof window === "undefined") return null;
  if (hasDecodedToken) return cachedDecodedToken;

  hasDecodedToken = true;
  try {
    const params = new URLSearchParams(window.location.search);
    const shareToken = params.get("jar");
    if (shareToken) {
      cachedDecodedToken = decodeNotesFromToken(shareToken);
    }
  } catch (e) {
    console.error("Error reading URL share token:", e);
  }
  return cachedDecodedToken;
}

// Build a compact delta: only store entries that differ from defaults
function buildDelta(notesList: string[]): Record<number, string> {
  const delta: Record<number, string> = {};
  for (let i = 0; i < defaultNotes.length; i++) {
    if (notesList[i] !== defaultNotes[i]) {
      delta[i] = notesList[i];
    }
  }
  return delta;
}

// Reconstruct full notes array from a delta
function applyDelta(delta: Record<number, string>): string[] {
  const out = defaultNotes.slice();
  for (const [key, value] of Object.entries(delta)) {
    const idx = Number(key);
    if (idx >= 0 && idx < out.length && typeof value === "string") {
      out[idx] = value;
    }
  }
  return out;
}

export function encodeNotesToToken(notesList: string[], recipient: string = "my love"): string {
  const delta = buildDelta(notesList);
  const payload = JSON.stringify({ d: delta, r: recipient });
  // lz-string compressToEncodedURIComponent produces a URL-safe compressed string
  return LZString.compressToEncodedURIComponent(payload);
}

export function decodeNotesFromToken(token: string): { notes: string[]; recipient: string } | null {
  try {
    const json = LZString.decompressFromEncodedURIComponent(token);
    if (!json) return null;
    const parsed = JSON.parse(json);

    // New compact delta format: { d: {index: note}, r: recipient }
    if (parsed && typeof parsed.d === "object" && !Array.isArray(parsed.d)) {
      return {
        notes: applyDelta(parsed.d),
        recipient: parsed.r || "my love",
      };
    }

    // Legacy fallback: old format was { notes: [...], recipient: "..." }
    if (parsed && Array.isArray(parsed.notes)) {
      return { notes: parsed.notes, recipient: parsed.recipient || "my love" };
    }

    // Even older fallback: raw array
    if (Array.isArray(parsed)) {
      return { notes: parsed, recipient: "my love" };
    }
  } catch (e) {
    // Maybe it's the old Base64 format — try legacy decode
    try {
      let base64 = token.replace(/-/g, "+").replace(/_/g, "/");
      while (base64.length % 4) base64 += "=";
      const binary = atob(base64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const json = new TextDecoder().decode(bytes);
      const parsed = JSON.parse(json);
      if (Array.isArray(parsed)) return { notes: parsed, recipient: "my love" };
      if (parsed && Array.isArray(parsed.notes))
        return { notes: parsed.notes, recipient: parsed.recipient || "my love" };
    } catch {}
    console.error("Failed to decode share token:", e);
  }
  return null;
}

export function loadRecipient(): string {
  if (typeof window === "undefined") return "my love";

  const decoded = getDecodedToken();
  if (decoded && decoded.recipient) return decoded.recipient;

  try {
    const raw = localStorage.getItem(RECIPIENT_STORAGE_KEY);
    return raw || "my love";
  } catch {
    return "my love";
  }
}

export function saveRecipient(name: string) {
  try {
    localStorage.setItem(RECIPIENT_STORAGE_KEY, name);
  } catch {}
}

export function loadNotes(): string[] {
  if (typeof window === "undefined") return defaultNotes;

  const decoded = getDecodedToken();
  if (decoded && decoded.notes) return decoded.notes;

  try {
    const raw = localStorage.getItem(NOTES_STORAGE_KEY);
    if (!raw) return defaultNotes;
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return defaultNotes;
    const out = defaultNotes.slice();
    for (let i = 0; i < out.length; i++) {
      if (typeof parsed[i] === "string" && parsed[i].trim().length > 0) {
        out[i] = parsed[i];
      }
    }
    return out;
  } catch {
    return defaultNotes;
  }
}

export function saveNotes(notes: string[]) {
  try {
    localStorage.setItem(NOTES_STORAGE_KEY, JSON.stringify(notes));
  } catch {}
}

export function useNotes(): string[] {
  const [notes, setNotes] = useState<string[]>(defaultNotes);
  useEffect(() => {
    setNotes(loadNotes());
    const onStorage = (e: StorageEvent) => {
      if (e.key === NOTES_STORAGE_KEY) setNotes(loadNotes());
    };
    window.addEventListener("storage", onStorage);
    return () => window.removeEventListener("storage", onStorage);
  }, []);
  return notes;
}